query_denied:
PREFIX li: <http://www.lifeinsurance.org/ontology#>
PREFIX li_abox: <http://www.lifeinsurance.org/ontology/abox#>
SELECT DISTINCT ?contractID ?sourceSection ?sourceText WHERE {
  ?policy li:sourceContractID ?contractID ;
          li:hasExclusion ?excl .
  ?excl a li:SurvivorshipExclusion .
  OPTIONAL { ?excl li:sourceSection ?sourceSection ; li:sourceText ?sourceText . }
}

PREFIX li: <http://www.lifeinsurance.org/ontology#>
PREFIX li_abox: <http://www.lifeinsurance.org/ontology/abox#>
SELECT DISTINCT ?contractID ?sourceSection ?sourceText WHERE {
  ?policy li:sourceContractID ?contractID ;
          li:hasProvision ?prov .
  ?prov a li:FreeLookProvision ;
        li:freeLookPeriodDays ?days .
  FILTER(?days < 20)
  OPTIONAL { ?prov li:sourceSection ?sourceSection ; li:sourceText ?sourceText . }
}
